import { createContext, useContext, useState, useEffect } from 'react';
import { HTMLHuelNotificationElement } from 'huel-notification';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

interface UseNotificationContextResult {
  notificationElem: HTMLHuelNotificationElement | null;
  notify: (props: NotificationProps) => Promise<void>;
}

const NotificationContext = createContext(null);

const useNotificationContext = (): UseNotificationContextResult => {
  const notificationElem = useContext(NotificationContext);
  const [notificationElemState, setNotificationElemState] = useState(notificationElem);

  useEffect(() => {
    setNotificationElemState(notificationElem);
  }, [notificationElem]);

  const notify = async (props: NotificationProps) => {
    if (!notificationElemState) return;

    const { heading, subheading, type } = props;
    await notificationElemState.open({
      heading,
      subheading,
      type,
    });
  };

  return { notificationElem: notificationElemState, notify };
};

export default useNotificationContext;
